import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import MovieDetail from './pages/MovieDetail';
import Player from './pages/Player';
import Channels from './pages/Channels';
import ChannelPlayer from './pages/ChannelPlayer';
import AdminPanel from './pages/admin/AdminPanel';
import AddMovie from './pages/admin/AddMovie';
import AddSeries from './pages/admin/AddSeries';
import AddChannel from './pages/admin/AddChannel';
import EditSeries from './pages/admin/EditSeries';
import EditMovie from './pages/admin/EditMovie';
import AddEpisode from './pages/admin/AddEpisode';
import './App.css';

function App() {
  return (
    <Router>
      <div className="App bg-stream-dark min-h-screen text-white font-sans selection:bg-stream-red selection:text-white">
        <Navbar />
        {/* Agregamos un padding top para evitar que el contenido quede detrás del navbar fijo */}
        <div className="pt-20">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/movie/:id" element={<MovieDetail />} />
            <Route path="/player/:id" element={<Player />} />
            <Route path="/channels" element={<Channels />} />
            <Route path="/player/channel/:id" element={<ChannelPlayer />} />
            <Route path="/admin" element={<AdminPanel />} />
            <Route path="/admin/add-movie" element={<AddMovie />} />
            <Route path="/admin/add-series" element={<AddSeries />} />
            <Route path="/admin/add-channel" element={<AddChannel />} />
            <Route path="/admin/add-episode" element={<AddEpisode />} />
            <Route path="/admin/edit-series/:id" element={<EditSeries />} />
            <Route path="/admin/edit-movie/:id" element={<EditMovie />} />
          </Routes>
        </div>
      </div>
    </Router>
  );
}

export default App;
